import{getReminders,setReminders}from"./storage.js";export async function scheduleReminder(e,t,n,r="note_reminder",i="",s="none"){if(n<Date.now())throw new Error("Cannot schedule a reminder in the past.");const a=await getReminders();return a[e]={id:e,type:r,title:t,description:i,scheduledAt:n,recurrence:s,createdAt:a[e]?.createdAt||Date.now(),active:!0},await setReminders(a),new Promise(t=>{chrome.runtime.sendMessage({type:"SCHEDULE_REMINDER",id:e,timestamp:n},t)})}export async function cancelReminder(e,t=!1){if(t){const t=await getReminders();t[e]&&(t[e].active=!1,await setReminders(t))}else{const t=await getReminders();delete t[e],await setReminders(t)}return new Promise(t=>{chrome.runtime.sendMessage({type:"CANCEL_REMINDER",id:e},t)})}